PRAGMA foreign_keys = ON;

-- Часть 28 из 28. Существующие тайтлы не перезаписываются.

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09892e0","title":"Жуй. Книга 1 (сборник)","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001269459/140/406a/Dzhon_Lajman_Rob_Gillori__Zhuj._Kniga_1_sbornik.jpg","isbn":"978-5-91996-062-1","publisher":"XL Media","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"У детектива Тони Чжуя есть один очень неприятный секрет. Чжуй - цибопат, а это значит, что он может получать экстрасенсорные видения от любой еды, которую попробует. А еще Чжуй не перед чем не остановится ради того, чтобы раскрыть преступление и найти виновного. Даже если это означает попробовать кусочек трупа жертвы, если в этом будет необходимость... Способности Тони оказываются чересчур пугающими для службы в обычной полиции, зато идеально подходят для работы в особом отделе Федеральной Службы Контроля Продуктов, самой могущественной правоохранительной организации в мире. Ему предстоит расследовать самые странные и загадочные нераскрытые дела. Перед вами невероятная нарезка из черного юмора, фантастики и умело обыгранных штампов полицейского боевика, приправленная обязательными ингредиентами второсортного кино: полицейскими, мошенниками, людоедами и экстрасенсами. Вас ждет незабываемое послевкусие и вы наверняка не откажетесь от добавки! В этой книге вас ждут две первые части серии: \"Вкус жизни\", попавшая в список бестселлеров \"Нью-Йорк Таймс\", и ее продолжение - \"Вкус без границ\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999072,"hdCover":""},{"id":"09892df","title":"Жуй. Книга 2 (сборник)","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001619248/140/018f/Dzhon_Lajman_Rob_Gillori__Zhuj._Kniga_2_sbornik.jpg","isbn":"978-5-91996-093-5","publisher":"XL Media","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"У детектива Тони Чжуя есть один очень неприятный секрет. Чжуй - цибопат, а это значит, что он может получать экстрасенсорные видения от любой еды, которую попробует. А еще Чжуй не перед чем не остановится ради того, чтобы раскрыть преступление и найти виновного. Даже если это означает попробовать кусочек трупа жертвы, если в этом будет необходимость... Способности Тони оказываются чересчур пугающими для службы в обычной полиции, зато идеально подходят для работы в особом отделе Федеральной Службы Контроля Продуктов, самой могущественной правоохранительной организации в мире. Ему предстоит расследовать самые странные и загадочные нераскрытые дела.  Перед вами невероятная нарезка из черного юмора, фантастики и умело обыгранных штампов полицейского боевика, приправленная обязательными ингредиентами второсортного кино: полицейскими, мошенниками, людоедами и экстрасенсами. Вас ждет незабываемое послевкусие и вы наверняка не откажитесь от добавки! В эту книгу вошли третья и четвертая части серии: \"Только десерт\" и \"Фламбе\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999071,"hdCover":""},{"id":"09892de","title":"人でなしの恋 / Hitodenashi no Koi Izumi Komitsukusu","author":"Хироаки Самура","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001447062/140/6491/Hiroaki_Samura__%E4%BA%BA%E3%81%A7%E3%81%AA%E3%81%97%E3%81%AE%E6%81%8B__Hitodenashi_no_Koi_Izumi_Komitsukusu.jpg","isbn":"978-4870766549","publisher":"Issuisya","pubDate":"2006","language":"Японский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999070,"hdCover":""},{"id":"09892dd","title":"Magneto, Volume 3: Shadow Games","author":"Cullen Bunn","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002066433/140/4ce4/Cullen_Bunn__Magneto_Volume_3_Shadow_Games.jpg","isbn":"","publisher":"Marvel","pubDate":"2015","language":"Английский","series":"","genres":[],"annotation":"In his war against those who would see his kind extinguished, Magneto has one steadfast ally: the mysterious woman called Briar Raleigh. But what are her true designs for the Master of Magnetism? On the island of Genosha, the backdrop for his greatest triumphs and most devastating tragedies, Magneto is confronted by S.H.I.E.L.D.! But the Master of Magnetism doesn''t stand alone...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999069,"hdCover":""},{"id":"09892dc","title":"Magneto Vol. 4: Last Days","author":"Paul Davidson,Каллен Банн","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002971904/140/5230/__Magneto_Vol._4_Last_Days.jpg","isbn":"","publisher":"Marvel","pubDate":"2015","language":"","series":"Magneto","genres":[],"annotation":"Earth is on a collision course with oblivion, and Magneto has just learned that time is running out. With everything he''s fought for being brought to an end, how will the Master of Magnetism spend his last days on Earth? Will he celebrate his legacy? Be tortured by his past? Or take it upon himself to stop the end of all things? Desperate to prevent the mutant race from its inevitable extinction, Magneto faces down the gruesome Sugar Man. But has the key to salvation been right in front of him all along — in the form of his daughter, Polaris? With Earth on the verge of destruction, the Master of Magnetism is determined to be mutantkind''s savior at long last — but what terrible price is he willing to pay?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999068,"hdCover":""},{"id":"09892db","title":"Человек-череп. Том 4","author":"Симамото Кадзухико,Исиномори Сетаро","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000955904/140/92a6/__Chelovekcherep._Tom_4.jpg","isbn":"978-5-7525-2916-0,  978-5-7525-2912-2,  978-4-8899-1726-0","publisher":"Фабрика комиксов","pubDate":"2014","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"У него забрали семью, лицо и саму душу, но он вернулся из страны мертвых, чтобы отомстить злодеям и заодно узнать, кто наделил его сверхъестественными способностями. В сопровождении верного помощника Гаро, в случае опасности трансформирующегося в огромных размеров волка, крокодила и летучую мышь, он идет по следу заказчика убийства своих родителей, но когда достигает цели, правда оказывается слишком ужасной даже для такого хладнокровного и бездушного мстителя, как он. Порвав с прошлым, он начинает бороться против таинственного синдиката, управляющего всем преступным миром страны. Он будет защищать людей. Он никогда не остановится. он будет испепелять врагов адским огнем, что бушует внутри него. Он - Человек-череп!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999067,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09892da","title":"Человек-череп. Том 3","author":"Симамото Кадзухико,Исиномори Сетаро","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000946333/140/5842/__Chelovekcherep._Tom_3.jpg","isbn":"978-5-7525-2915-3,  978-5-7525-2912-2,  978-4-8899-1716-1","publisher":"Фабрика комиксов","pubDate":"2014","language":"Русский","series":"Сыщик Патмосов","genres":["Комиксы","манга","графические романы"],"annotation":"У него забрали семью, лицо и саму душу, но он вернулся из страны мертвых, чтобы отомстить злодеям и заодно узнать, кто наделил его сверхъестественными способностями. В сопровождении верного помощника Гаро, в случае опасности трансформирующегося в огромных размеров волка, крокодила и летучую мышь, он идет по следу заказчика убийства своих родителей, но когда достигает цели, правда оказывается слишком ужасной даже для такого хладнокровного и бездушного мстителя, как он. Порвав с прошлым, он начинает бороться против таинственного синдиката, управляющего всем преступным миром страны. Он будет защищать людей. Он никогда не остановится. он будет испепелять врагов адским огнем, что бушует внутри него. он - человек-череп!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999066,"hdCover":""},{"id":"09892d9","title":"Человек-череп. Том 2","author":"Симамото Кадзухико,Исиномори Сетаро","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000942108/140/d90b/__Chelovekcherep._Tom_2.jpg","isbn":"978-5-7525-2914-6,  978-5-7525-2912-2,  978-4-8899-1708-6","publisher":"Фабрика комиксов","pubDate":"2014","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"У него забрали семью, лицо и саму душу, но он вернулся из страны мертвых, чтобы отомстить злодеям и заодно узнать, кто наделил его сверхъестественными способностями. В сопровождении верного помощника Гаро, в случае опасности трансформирующегося в огромных размеров волка, крокодила и летучую мышь, он идет по следу заказчика убийства своих родителей. Но когда достигает цели, правда оказывается слишком ужасной даже для такого хладнокровного и без-душного мстителя, как он. Порвав с прошлым, он начинает бороться против таинственного синдиката, управляющего всем преступным миром страны. Он будет защищать людей. Он никогда не остановится. Он будет испепелять врагов адским огнем, что бушует внутри него. Он - Человек-череп!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999065,"hdCover":""},{"id":"09892d8","title":"День революционера","author":"Дзиро Мацумото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002472588/140/7b72/Dziro_Matsumoto__Den_revolyutsionera.jpg","isbn":"978-5-905295-37-9","publisher":"Alt Graph","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«День революционера» — сборник из пяти разношёрстных историй от одного из самых необычных и неоднозначных авторов сэйнэн-манги Дзиро Мацумото, известного своими работами «Фризия» и «Дикая планета». Истории не объединены общим сюжетом, но их связывает иррациональность окружающей действительности и трагикомичность нашей жизни.  Это книга полна иронии, чёрного юмора, сюрреализма и, конечно, насилия и секса. Срез жизни, который автор мастерский преподносит в своем фирменном стиле, одновременно реалистичном и карикатурном, сказочном и хулиганском. Эта манга рассмешит вас или заставит задуматься, но точно не даст заскучать!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999064,"hdCover":""},{"id":"09892d7","title":"Странники. Том 1","author":"Макото Юкимура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002872217/140/9a9e/Makoto_Yukimura__Stranniki._Tom_1.jpg","isbn":"978-5-905295-47-8","publisher":"Alt Graph","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"На дворе 2074 год. Человечество покоряет орбиты ближайших планет и разрабатывает месторождения экзотических ресурсов по всей Солнечной системе, но даже на новых горизонтах люди остаются теми же, что на Земле. Они привносят в космос свои земные проблемы: взаимную ненависть, социальное неравенство, загрязнение окружающей среды, извечный поиск себя и тоску по неизведанному. Но, как и на старушке Земле, на просторах космоса найдутся те, кто будет противостоять извечным проблемам человечества своей целеустремлённостью, трудолюбием и надеждой на лучшее. На стареньком и потрёпанном космическом мусоросборщике, который очищает земную орбиту от списанных спутников, различных обломков и прочего мусора, работает разношёрстная команда: самоуверенный мечтатель Хатимаки, грезящий о собственном космическом корабле, молчаливый Юрий, медитирующий на остатки разбитых спутников, и грозная капитан Фи, подчас готовая на всё ради сигареты. Они не герои галактики. И на первый взгляд их опасная работёнка может показаться скучной и однообразной. Но среди старого хлама всегда можно отыскать что-то неожиданное: начиная от сентиментальных ценностей и заканчивая мировым заговором. Пристегните ремни, ключ на старт — одиссея космических странников начинается!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999063,"hdCover":""},{"id":"09892d6","title":"Своими глазами","author":"Кэйдзи Накадзава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002086660/140/49af/Kejdzi_Nakadzava__Svoimi_glazami.jpg","isbn":"978-5-905295-33-1","publisher":"Alt Graph","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Своими глазами» — автобиографический рассказ Кэйдзи Накадзавы, опубликованный в 1972 году в журнале Monthly Shonen Jump. На страницах этого рассказа Кэйдзи Накадзава впервые поделился с широкой публикой своими воспоминаниями о войне, ядерном взрыве, а также о тяготах и лишениях, которые преследовали его семью в послевоенные годы. Эта история вызвала широкий резонанс в японском обществе, где тема ядерных бомбардировок Хиросимы и Нагасаки оставалась негласным табу на протяжении долгих лет. Именно рассказ «Своими глазами» подтолкнул Кэйдзи Накадзаву на создание его самой известной манги — «Босоногого Гэна».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999062,"hdCover":""},{"id":"09892d5","title":"Fatale #1","author":"Ed Brubaker","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000529082/140/7612/Ed_Brubaker__Fatale_1.jpg","isbn":"","publisher":"","pubDate":"2012","language":"","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999061,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
