  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09892d4","title":"Город, в котором меня нет. Том 1","author":"Кэй Самбэ","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002845010/140/63a8/Kej_Sambe__Gorod_v_kotorom_menya_net._Tom_1.jpg","isbn":"978-5-907014-30-5","publisher":"Истари Комикс","pubDate":"2018","language":"Русский","series":"Город, в котором меня нет","genres":["Комиксы","манга","графические романы"],"annotation":"Жизнь Сатору Фудзинумы не задалась — ему почти тридцать, а он так и не нашёл своего места в мире. Кроме будничных невзгод ему приходиться мириться ещё и со странным феноменом, «перемоткой», о котором не знает больше никто. Но вскоре одно событие целиком переворачивает его жизнь, разделив её на «до» и «после». Гибель одноклассников, дело серийного убийцы, похищавшего детей, близкий друг, которого он не смог защитить, и неразгаданная тайна личности преступника заставляют Сатору заглянуть в прошлое, и его настоящее начинает меняться.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999060,"hdCover":""},{"id":"09892d3","title":"Нелюдь. Том 1","author":"Гамон Сакураи,Цуйна Миура","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002603019/140/1751/__Nelyud._Tom_1.jpg","isbn":"978-5-91996-125-3","publisher":"XL Media","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Семнадцать лет назад в Африке обнаружили первого из так называемых нелюдей - существ, которые внешне неотличимы от людей, но которых невозможно убить. Это открытие стало для человечества событием огромного масштаба, но спустя годы шумиха улеглась: хотя нелюди по-прежнему невероятно важны для мировых правительств и научных лабораторий, на жизнь простых обывателей их существование почти никакого влияния не оказывает.  Обычный старшеклассник Кэй Нагаи никогда не думал, что когда-нибудь столкнется с этими полумифическими существами. Но однажды он попадает в аварию и по всем известным законам медицины должен умереть - но... почему-то не умирает. И тут же становится объектом жестокой охоты...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999059,"hdCover":""},{"id":"09892d2","title":"Blame! Том 1","author":"Цутому Нихэй","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002326163/140/ee57/Tsutomu_Nihej__Blame_Tom_1.jpg","isbn":"978-5-91996-130-7","publisher":"XL Media","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Может быть, на Земле… Может быть, в далеком будущем… В мире, называемом Мегаструктурой, – невероятном по размерам многоуровневом лабиринте, населенном последними представителями человечества и всевозможными странными существами частично или полностью небиологического происхождения, – молодой человек по имени Килли, преодолевая этаж за этажом, постепенно поднимается наверх. Он ищет Сетевые Терминальные Гены, с помощью которых можно подключиться к Сетевой сфере, но носителей этих генов почти не осталось. Увенчаются ли успехом поиски Килли?  Архитектор по профессии, Цутому Нихэй смог создать удивительный, уникальный мир, где сочетаются техногенные образы далекого будущего и мрачный дух постапокалиптики. Манга «Blame!» – один из общепризнанных шедевров научной фантастики, прославившийся благодаря как уникальному художественному стилю, так и неповторимой атмосфере безысходности и тайны.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999058,"hdCover":""},{"id":"09892d1","title":"Redrum 327. Том 1","author":"Я Сен Ко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000316163/140/0bba/Ya_Sen_Ko__Redrum_327._Tom_1.jpg","isbn":"978-5-7525-1823-2,  978-5-7525-1822-5,  89-528-5911-1,  978-985-16-5972-8","publisher":"Харвест, Фабрика комиксов","pubDate":"2008","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Отправлялись на выходные в уединенный горный коттедж, семеро студентов университета и представить не могли, что их романтический уикенд превратится в настоящий кошмар. Появление новичка - прекрасной и загадочной девушки по имени Гаэ - вносит разлад в компанию старых друзей. Мрачная атмосфера пронизываемого холодными ветрами дома пробуждает в душе подростков навязчивые воспоминания о давнишней трагедии, которая, казалось, была забыта навсегда. Мелкие ссоры, любовные трагедии, сведение старых счетов - все это стало только прелюдией к ужасу, воцарившемуся под сводами виллы, когда обнаружилась пропажа одной из девушек. Кто затаился в окружающей дом темноте? Кто перерезал телефонные провода и вывел из строя единственную машину? Отрезанные от внешнего мира, преследуемые неведомым маньяком, друзья с замиранием сердца ждут очередного удара неумолимого рока. Новая манхва Я-Сен Ко выполнена в лучших традициях \"Сияния\" С.Кинга и \"Крика\" У.Крейвена.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999057,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
