)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09892d0","title":"Redrum 327. Том 2","author":"Я Сен Ко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000315985/140/0bba/Ya_Sen_Ko__Redrum_327._Tom_2.jpg","isbn":"978-5-7525-1828-7,  978-5-7525-1822-5,  89-528-5911-1,  89-528-5910-3","publisher":"Фабрика комиксов","pubDate":"2009","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Отправляясь на выходные в уединенный горный коттедж, семеро студентов университета и предста­вить не могли, что их романтический уикенд Пре­вратится в самый настоящий кошмар. Появление новичка, прекрасной и загадочной девушки по имени Газ, вносит разлад в компанию старых друзей. Мрачная атмосфера пронизываемого колодными ветрами доме пробуждает в душе подростков навяз­чивые воспоминания о давнишней трагедии, кото­рая, казалось, была забыта навсегда. Мелкие ссоры, любовные трагедии, сведение старых счетов -все это становится лишь прелюдией к ужасу, обрушивающемуся на молодых людей с приходом ночи. Кто прячется в темных закоулках дома? Кто -вывел из строя телефонную линию, соединявшую обитателей виллы с внешним миром? Потерявшие надежду на помощь извне, преследуемые неведо­мым маньяком друзья с замиранием сердца ждут очередного удара неумолимого рока, Новая манхва. Я Сен Ко выполнена в лучших традициях \"\"Сияния\"\" С, Кинга и \"\"Крика\"\" У. Крейвена.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999056,"hdCover":""},{"id":"09892cf","title":"Redrum 327. Том 3","author":"Я Сен Ко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000441416/140/114b/Ya_Sen_Ko__Redrum_327._Tom_3.jpg","isbn":"978-5-7525-2638-1","publisher":"Фабрика комиксов","pubDate":"2010","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Отправляясь на выходные в уединенный горный коттедж, семеро студентов университета и представить не могли, что их романтический уикенд превратится в самый настоящий кошмар. Появление новичка, прекрасной и загадочной девушки по имени Гаэ, вносит разлад в компанию старых друзей. Мрачная атмосфера пронизываемого холодными ветрами дома пробуждают в душе подростков навязчивые воспоминания о давнишней трагедии, которая, казалось, была забыта навсегда. Мелкие ссоры, любовные трагедии, сведение старых счетов - все это становится лишь прелюдией к ужасу, обрушивающемуся на молодых людей с приходом ночи...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999055,"hdCover":""},{"id":"09892ce","title":"Деревья. Книга 2","author":"Уоррен Эллис,Джейсон Говард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002811263/140/657a/__Derevya._Kniga_2.jpg","isbn":"978-5-04-095321-9","publisher":"Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы. Современная классика","genres":["Комиксы","манга","графические романы"],"annotation":"Десять лет, как они приземлились на Землю. Их явление знаменует скорый конец света. Отомстят ли герои Деревьям за внезапное вторжение?  Завершение НФ-новеллы Уоррена Эллиса («Трансметрополитен», «РЭД») и Джейсона Говарда («Супердинозавр», «Удивительный Человек-волк»).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999054,"hdCover":""},{"id":"09892cd","title":"Деревья. Книга 1","author":"Уоррен Эллис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002785726/140/a17b/Uorren_Ellis__Derevya._Kniga_1.jpg","isbn":"978-5-04-094468-2","publisher":"Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы. Современная классика","genres":["Комиксы","манга","графические романы"],"annotation":"Первая книга повествует о ближайшем будущем человечества, проходящем в тени Деревьев. Несколько судеб, объединенных страшной тайной: в Китае молодой художник прибывает в «специальную культурную зону» под Деревом. молодая женщина в Италии под опасным покровительством нацистской банды встречает старика, который хочет обучить её ужасным умениям. группа ученых на Шпицбергене случайно обнаруживает, что Деревья вовсе «не спят», а представляют ужасную опасность.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999053,"hdCover":""},{"id":"09892cc","title":"Ultimate Comics Ultimates By Jonathan Hickman, Vol. 2","author":"Эсад Рибич,Люк Росс,Sam Humphries,Джонатан Хикман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002955138/140/4342/__Ultimate_Comics_Ultimates_By_Jonathan_Hickman_Vol._2.jpg","isbn":"9780785157205","publisher":"Marvel","pubDate":"2013","language":"Английский","series":"Ultimate Comics Ultimates","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999052,"hdCover":""},{"id":"09892cb","title":"Batman: Detective Comics Vol. 3: Greetings from Gotham","author":"Питер Дж. Томаси","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005904267/140/cac2/Piter_Dzh._Tomasi__Batman_Detective_Comics_Vol._3_Greetings_from_Gotham.jpg","isbn":"978-1401288617","publisher":"DC Comics","pubDate":"2020","language":"","series":"Detective Comics","genres":[],"annotation":"Following the events of Detective Comics Vol. 2: Arkham Knight, Batman''s limits will be pushed to the limit as he faces off against some of his deadliest foes including Deadshot and The Joker!  Detective Jim Corrigan has been shot on the streets of Gotham City--and the Spectre must reach out to Batman to help him find the secret assassin! There''s only one life Batman would be willing to risk saving Jim Corrigan and the Spectre: his own! Plus, Deadshot has returned to Gotham City following a long stint with the Suicide Squad, and Batman fears that without the oversight of Amanda Waller, Floyd Lawton will go back to his old ways.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999051,"hdCover":""},{"id":"09892ca","title":"That Texas Blood, Volume 1","author":"Крис Кондон","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005883762/140/8389/Kris_Kondon__That_Texas_Blood_Volume_1.jpg","isbn":"978-1534318069","publisher":"Image Comics","pubDate":"2021","language":"","series":"That Texas Blood","genres":[],"annotation":"After an explosive confrontation over a casserole dish, Joe Bob Coates begins to question his effectiveness as Sheriff of Ambrose County, Texas. Matters only get worse as Los Angeles-based writer Randy Terrill returns home following the sudden and mysterious death of his brother, causing a spiral down into a past filled with treachery and blood.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999050,"hdCover":""},{"id":"09892c9","title":"Dead Body Road, Volume 2: Bad Blood","author":"Джастин Джордан","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005883717/140/bbbb/Dzhastin_Dzhordan__Dead_Body_Road_Volume_2_Bad_Blood.jpg","isbn":"978-1534317215","publisher":"Image Comics","pubDate":"2021","language":"","series":"Dead Body Road","genres":[],"annotation":"Bree Hale has left a lot behind in her life. Crime. The military. But she can''t leave behind her own family, and when the local crime boss puts a hit out on her brother, there''s nothing she won''t do to save him. Absolutely nothing.  Skybound’s pulse-pounding action-crime series returns, with writer Justin Jordan (REAVER, The Strange Talent of Luthor Strode) and artist Benjamin Tiesma delivering an explosive tale of revenge like you’ve never seen before!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999049,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09892c8","title":"Новый Призрачный Гонщик. Том 2. Легенда","author":"Фелипе Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001668538/140/e5da/Felipe_Smit__Novyj_Prizrachnyj_Gonschik._Tom_2._Legenda.jpg","isbn":"978-5-91339-410-1","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Впервые за долгое время жизнь Робби Рейеса идёт в гору. Он немало зарабатывает на гонках, а его братец, Гейб, наконец-то получает то внимание, которое было ему необходимо. Но серийный убийца-сатанист Эли Морроу кое-что припас для своего юного носителя, и это уж точно не богато наследство или физиотерапия. Адские искры летят вовсе стороны, ведь легенда столкнётся с современностью: Джонни Блейз, оригинальный Призрачный Гонщик, и Робби Рейес! Олдскул и ньюскул, опыт и молодость, Восток и Запад — Призрачный Гонщик и Призрачный Гонщик! А также: вместе с развивающимися силами, Робби узнаёт шокирующую правду о пропавших родителях — но что ждёт Гейба? И чего на самом деле добивается Эли? Финишная черта уже рядом, и Робби предстоит сражение не с одним Духом Возмездия.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999048,"hdCover":""},{"id":"09892c7","title":"Новый Призрачный Гонщик. Том 1. Двигатели возмездия","author":"Трэдд Мур,Фелипе Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001519975/140/af4e/__Novyj_Prizrachnyj_Gonschik._Tom_1._Dvigateli_vozmezdiya.jpg","isbn":"978-5-91339-366-1","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Где-то в одном из районов Восточного Лос-Анджелеса, полном банд, перестрелок и наркоторговли, Робби Рейес получает невероятную новую силу! Но сможет ли подросток справиться с ней, или же она заведёт его на путь разрушений? В преступном мире назревает война, на улицах Восточного Лос-Анджелеса то здесь, то там вспыхивают стычки группировок из-за усиливающего наркотика, созданного Доктором Кельвином Забо, а Мистер Хайд пускает в ход дьявольский план по расширению своей преступной империи. И вот, встретив таинственную сущность, повинующуюся ему, примет ли Робби этого духа и как далеко он зайдёт, охраняя район? Новый Призрачный Гонщик встретится с Мистером Хайдом в этом драйвовом комиксе, неожиданный финал которого собьёт вас на скорости 160 км/ч!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999047,"hdCover":""},{"id":"09892c6","title":"Веном. Край, где обитают убийцы","author":"Каллен Банн,Каленн Банн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005614941/140/2fe3/__Venom._Kraj_gde_obitayut_ubijtsy.jpg","isbn":"978-5-91878-368-9","publisher":"Фантастика Книжный Клуб","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Агент Веном выходит на улицы ради старой доброй борьбы с преступностью... Но криминал не сдаётся, и Лорд Огр, вожак уголовного мира Филадельфии, объявляет войну самозваному защитнику города! Хладнокровные убийцы лезут из всех щелей, стремясь получить награду за голову Венома, его личность раскрывают, и теперь Флэшу Томпсону понадобится любая помощь — хотя бы для того, чтобы выжить. Положение ещё больше усложняется, когда в схватку вступает новая симбиотическая сущность: доблестный поступок Юджина случайно приводит к рождению Мании! Можно ли справиться с этой новой опасностью? И кто такая Мания — друг или враг?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999046,"hdCover":""},{"id":"09892c5","title":"Punisher: Frank Castle Max - Welcome to the Bayou","author":"Виктор Гишлер,Горан Парлов","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003193048/140/f763/__Punisher_Frank_Castle_Max__Welcome_to_the_Bayou.jpg","isbn":"978-0785133780","publisher":"Marvel","pubDate":"2009","language":"Английский","series":"","genres":[],"annotation":"Traveling the Louisiana back roads with something awful stored in his trunk, Frank Castle stops at a service station on the edge of the bayou... and steps into a world of unspeakable horror! Patrolling the depths of hell, the Punisher has crossed paths with some unsavory characters, but nothing has prepared him for the unspeakable depravity of the Geautreauxs.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999045,"hdCover":""},{"id":"09892c4","title":"Punisher Presents: Barracuda MAX","author":"Гарт Эннис","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003193052/140/9484/Gart_Ennis__Punisher_Presents_Barracuda_MAX.jpg","isbn":"978-0785124658","publisher":"Marvel","pubDate":"2007","language":"Английский","series":"","genres":[],"annotation":"The Punisher''s wildest foe is back. This time he''s embarking on a solo mission of playing bodyguard to the son of a dangerous mob boss. Junior is a hemophiliac - and every crime syndicate in the country can''t wait to take a shot at him as payback to his dad.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999044,"hdCover":""},{"id":"09892c3","title":"Untold Tales of Punisher Max","author":"Джейсон Старр","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001849773/140/58b9/Dzhejson_Starr__Untold_Tales_of_Punisher_Max.jpg","isbn":"9780785165927","publisher":"MAX","pubDate":"2012","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"PunisherMAX returns for another round as talented creators including JASON LATOUR (BPRD, Loose Ends) and award-winning crime novelist JASON STARR bring their unique visions to the gritty MAX world of Frank Castle! A massive debt, a gun with untraceable bullets, and one unthinkable choice. Whose side will the Punisher take? Frank gets involved in the most twisted encounter ever. COLLECTING: UNTOLD TALES OF PUNISHER MAX 1-5","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999043,"hdCover":""},{"id":"09892c2","title":"Punisher: Frank Castle Max - Six Hours to Kill","author":"Дуэйн Сверчински,Michael A. LaCombe","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003193046/140/1669/__Punisher_Frank_Castle_Max__Six_Hours_to_Kill.jpg","isbn":"978-0785131823","publisher":"Marvel","pubDate":"2009","language":"Английский","series":"","genres":["Триллеры"],"annotation":"The Punisher always knew he''d die on the job. But he didn''t know he''d have an expiration date. After busting up a slave ring in downtown Philadelphia, Frank Castle has been tricked, trapped, gassed, strapped to a table, and injected with a serum that will turn him into a 220-pound corpse by dawn - six hours from now. The people who grabbed him want him to do a simple little job and then they''ll give him the antidote - simple, right? Guess again! The Punisher is nobody''s errand boy! There''s only one thing he wants to do before he dies: Take as many bastards as he can with him!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999042,"hdCover":""},{"id":"09892c1","title":"Guardians of the Galaxy, Vol. 1: It''s On Us","author":"Эл Юинг,Juann Cabal","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005139384/140/a509/__Guardians_of_the_Galaxy_Vol._1_It039s_On_Us.jpg","isbn":"9781302920753","publisher":"Marvel","pubDate":"2020","language":"Английский","series":"","genres":[],"annotation":"Once they were a team of misfits. Now they''re a family, and they''ve earned their peace. But the universe is not a peaceful place - and it''s only getting worse. The Great Empires are in turmoil. The rule of law is dead. And amid the chaos, the gods of Olympus have returned - harbingers of a new age of war, reborn to burn their mark on the stars themselves. Someone has to guard the galaxy - but who will accept the mission? And will they survive it? Al Ewing (IMMORTAL HULK) and Juann Cabal (FRIENDLY NEIGHBORHOOD SPIDER-MAN) bring you in on the ground floor of a whole Marvel Universe of action and suspense! COLLECTING: GUARDIANS OF THE GALAXY (2020) 1-6","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999041,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09892c0","title":"Daredevil Vol 1 (#1-394)","author":"Фрэнк Миллер,Марв Вульфман,Стив Гербер,Рой Томас,Ann Nocenti,Roger McKenzie,показать всех","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001446109/140/3a2a/__Daredevil_Vol_1_1394.jpg","isbn":"","publisher":"Marvel Comics","pubDate":"1964","language":"","series":"","genres":[],"annotation":"The series that introduced Daredevil, the Man Without Fear! Daredevil’s first ongoing solo series. Unlike many Marvel heroes launched during the Silver Age of Comics, Daredevil debuted in his own series without first being test launched in another title. The series started in 1964 and lasted 380 issues until being cancelled in 1998. The series returned to its original numbering with issue #500 in Oct. 2009.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999040,"hdCover":""}]');

