FROM json_each('[{"id":"09892bf","title":"Essential Daredevil Volume 3 TPB (Essential)","author":"Гэри Фридрих","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000204174/140/edfb/Geri_Fridrih__Essential_Daredevil_Volume_3_TPB_Essential.jpg","isbn":"0785117245","publisher":"","pubDate":"2005","language":"Русский","series":"","genres":["Зарубежное фэнтези"],"annotation":"Book DescriptionDaredevil''s original identity crisis kicks off a collection of Colan classics! The ups and downs of his doomed love for Karen Page begin here! And DD goes Hollywood with the Stuntmaster and Brother Brimstone, but is any star as big","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999039,"hdCover":""},{"id":"09892be","title":"Marvel Knights: Defenders of the Streets","author":"Чак Диксон,Eduardo Barreto,Mike Lilly","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004474818/140/364b/__Marvel_Knights_Defenders_of_the_Streets.jpg","isbn":"978-1302912130","publisher":"Marvel","pubDate":"2018","language":"","series":"Marvel Knights (Book 1)","genres":[],"annotation":"Daredevil! Black Widow! Dagger! Shang-Chi! And...the Punisher?! What terrible evil could unite these vigilantes on a single mission? Would you believe...Ulik the Troll?! As DD leads them deep underground in search of answers, is Ulik really the priority - or is it taking down Frank Castle? How about helping Dagger''s troubled partner Cloak? Could it be Zaran the Weapons Master, who is leaving a trail of bodies in his wake? Or maybe it''s the ancient menace that Zaran is working for! Whatever the biggest problem faced by this vigilante team, only Moon Knight would be crazy enough to want in! Doctor Strange makes a house call as the group faces a nightmarish enemy, while Widow takes Dagger under her wing. All this plus Nick Fury, Luke Cage, and the final face-off between the Punisher and Daredevil!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999038,"hdCover":""},{"id":"09892bd","title":"Daredevil","author":"","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001850917/140/a9ef/Marvel_Comics__Daredevil.jpg","isbn":"9780785193265","publisher":"","pubDate":"2015","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999037,"hdCover":""}]');
